('VTJ_2020_consolidated', 'VTJ', 2020, 'consolidated', 'Công ty TNHH Kiểm toán AFC Việt Nam – Chi nhánh Hà Thành', 'unqualified', 0, NULL),
('VTI_2025_consolidated', 'VTI', 2025, 'consolidated', 'Công ty TNHH Kiểm toán An Việt', 'qualified', 1, 'Công ty có lỗ lũy kế khoảng 261,710 tỷ đồng, vốn chủ sở hữu âm 216,983 tỷ đồng, nợ ngắn hạn vượt tài sản ngắn hạn 218,019 tỷ đồng. Việc cải thiện tình hình tài chính phụ thuộc vào việc tái cấu trúc tài chính và sự hỗ trợ từ các bên liên quan. Công ty đã được các cá nhân tạm ứng 196,896 tỷ đồng để có nguồn tiền thanh toán và đang tiếp tục thảo luận về chuyển quyền đòi nợ.'),
('VTI_2023_consolidated', 'VTI', 2023, 'consolidated', 'Công ty TNHH Kiểm toán An Việt', 'qualified', 1, 'Công ty có lỗ lũy kế khoảng 271.430 tỷ đồng, vốn chủ sở hữu âm 226.703 tỷ đồng, nợ ngắn hạn vượt tài sản ngắn hạn khoảng 229.933 tỷ đồng. Việc cải thiện phụ thuộc vào tái cấu trúc tài chính và sự hỗ trợ từ các bên liên quan.'),
('VTI_2024_consolidated', 'VTI', 2024, 'consolidated', 'Công ty TNHH Kiểm toán An Việt', 'qualified', 1, 'Tại ngày 31/12/2024, Công ty có lỗ lũy kế khoảng 268,041 tỷ đồng; vốn chủ sở hữu âm 223,314 tỷ đồng; số dư nợ ngắn hạn vượt quá tài sản ngắn hạn khoảng 226,444 tỷ đồng. Việc cải thiện tình hình tài chính, khả năng thanh toán ngắn hạn phụ thuộc vào việc tái cấu trúc tài chính và sắp xếp nguồn tài chính, hỗ trợ từ các bên liên quan của Công ty. Công ty đã ký biên bản thỏa thuận với một số cá nhân bán nợ phải thu, các cá nhân đã tạm ứng trước 196.9 tỷ đồng, tuy nhiên chưa ký kết hợp đồng mua bán nợ chính thức.');
INSERT OR REPLACE INTO `audit_reports` (`id`, `ticker`, `year`, `report_type`, `auditor_name`, `audit_opinion`, `going_concern_issue`, `going_concern_detail`) VALUES
('VTI_2022_consolidated', 'VTI', 2022, 'consolidated', 'An Việt CPA', 'qualified', 1, 'Tại ngày 31/12/2022, Công ty có lỗ lũy kế khoảng 315,894 tỷ đồng làm cho vốn chủ sở hữu âm 271,167 tỷ đồng, số dư nợ ngắn hạn vượt quá tài sản ngắn hạn khoảng 261,656 tỷ đồng. Công ty gặp khó khăn về tài chính và thanh toán, phụ thuộc vào sự hỗ trợ từ Công ty mẹ - Tập đoàn Dệt may Việt Nam.'),
('VTI_2021_consolidated', 'VTI', 2021, 'consolidated', 'Công ty TNHH KPMG Việt Nam', 'qualified', 1, 'Tại ngày 31 tháng 12 năm 2021, nợ ngắn hạn đã vượt quá tài sản ngắn hạn là 268.724 triệu VND và tổng nợ phải trả đã vượt quá tổng tài sản là 271.288 triệu VND. Công ty có một số khoản vay đã quá hạn trị giá 182.131 triệu VND. Giá trị của giả định hoạt động liên tục phụ thuộc vào việc công ty mẹ, Tập đoàn Dệt may Việt Nam, tiếp tục cung cấp hỗ trợ tài chính.'),
('VTI_2020_consolidated', 'VTI', 2020, 'consolidated', 'KPMG Việt Nam', 'qualified', 1, 'Tại ngày 31 tháng 12 năm 2020, nợ ngắn hạn đã vượt quá tài sản ngắn hạn là 263.908 triệu VND và tổng nợ phải trả đã vượt quá tổng tài sản là 262.727 triệu VND. Công ty có các khoản vay đáng kể cần tái trợ trong vòng 12 tháng kế tiếp, với số khoản vay đã quá hạn là 186.091 triệu VND, cho thấy sự tồn tại của các yếu tố không chắc chắn trọng yếu có thể gây nghi ngờ về khả năng tiếp tục hoạt động.'),
('VTI_2019_consolidated', 'VTI', 2019, 'consolidated', 'Công ty TNHH KPMG Việt Nam', 'qualified', 1, 'Công ty nợ ngắn hạn vượt tài sản ngắn hạn 264.104 triệu VND, tổng nợ phải trả vượt tổng tài sản 262.746 triệu VND. Có các khoản vay đáng kể cần tái tài trợ và khoản vay đã quá hạn 189.123 triệu VND. Khả năng tiếp tục hoạt động phụ thuộc vào sự hỗ trợ tài chính từ công ty mẹ Tập đoàn Dệt May Việt Nam.'),
('VTI_2018_consolidated', 'VTI', 2018, 'consolidated', 'KPMG Việt Nam', 'unqualified', 1, 'Nợ ngắn hạn vượt quá tài sản ngắn hạn 264.139 triệu VND (1/1/2018: 133.374 triệu VND), tổng nợ phải trả vượt quá tổng tài sản 262.746 triệu VND (1/1/2018: 246.137 triệu VND). Công ty có các khoản vay đáng kể cần tái tài trợ trong 12 tháng tới. Công ty dựa hoàn toàn vào hỗ trợ tài chính từ công ty mẹ Tập đoàn Dệt May Việt Nam. Vốn chủ sở hữu âm với lỗ lũy kế 307.473 triệu VND.'),
('VTI_2016_consolidated', 'VTI', 2016, 'consolidated', 'Công ty TNHH KPMG Việt Nam', 'unqualified', 1, 'Báo cáo tài chính được lập trên cơ sở hoạt động liên tục mặc dù nợ ngắn hạn vượt quá tài sản ngắn hạn 44.625 triệu VND và tổng nợ phải trả vượt quá tổng tài sản 196.935 triệu VND. Công ty có các khoản vay đáng kể cần tái tài trợ trong 12 tháng tới, cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể gây nghi ngờ về khả năng tiếp tục hoạt động.'),
