('VTA_2025_consolidated', 'VTA', 2025, 'consolidated', 'Công ty TNHH Kiểm toán CPA VIETNAM', 'unqualified', 1, 'Công ty đã ngừng hoạt động sản xuất từ tháng 11 năm 2024 cho đến hết năm 2025. Các khoản nợ ngắn hạn đã vượt quá tài sản ngắn hạn 49.137.482.604 VND. Lỗ lũy kế 102.243.618.746 VND làm thâm hụt vốn chủ sở hữu 11.461.418.746 VND. Điều kiện này cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục.'),
('VTA_2024_consolidated', 'VTA', 2024, 'consolidated', 'Công ty TNHH Kiểm toán CPA VIETNAM', 'unqualified', 1, 'Tại ngày 31/12/2024, nợ ngắn hạn của Công ty đã vượt quá tài sản ngắn hạn 47.054.994.209 VND. Công ty lỗ 34.987.921.159 VND trong năm và có lỗ lũy kế 85.127.527.792 VND. Công ty đã ngừng sản xuất từ 11/2024 đến 02/2025. Khả năng hoạt động liên tục phụ thuộc vào quyết định của cổ đông lớn và kế hoạch tái cơ cấu.'),
('VTA_2023_consolidated', 'VTA', 2023, 'consolidated', 'Công ty TNHH Kiểm toán CPA VIETNAM', 'unqualified', 1, 'Tại ngày 31/12/2023, các khoản nợ ngắn hạn của Công ty đã vượt quá tài sản ngắn hạn số tiền 28.117.348.195 VND. Công ty có kết quả kinh doanh lỗ 28.541.560.957 VND và khoản lỗ lũy kế là 50.712.106.001 VND. Khả năng tiếp tục hoạt động phụ thuộc vào sự hỗ trợ tài chính từ các chủ đầu tư, khả năng thu hồi các khoản phải thu, gia hạn nợ với các nhà cung cấp, bên cho vay và hiệu quả hoạt động kinh doanh trong tương lai.'),
('VTA_2022_consolidated', 'VTA', 2022, 'consolidated', 'CPA Vietnam', 'unqualified', 0, NULL),
('VTA_2021_consolidated', 'VTA', 2021, 'consolidated', 'CÔNG TY TNHH KIỂM TOÁN CPA VIETNAM', 'unqualified', 0, NULL),
('VTA_2020_consolidated', 'VTA', 2020, 'consolidated', 'CPA VIETNAM', 'unqualified', 0, NULL),
('VTE_2023_consolidated', 'VTE', 2023, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 0, NULL),
('VTA_2016_consolidated', 'VTA', 2016, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn Chuẩn Việt - VIETVALUES', 'unqualified', 0, NULL),
('VTA_2017_consolidated', 'VTA', 2017, 'consolidated', 'VIETVALUES', 'unqualified', 0, NULL),
('VST_2025_consolidated', 'VST', 2025, 'consolidated', 'AASC Auditing Firm', 'qualified', 1, 'Tại thời điểm 31/12/2025, nợ ngắn hạn đã vượt quá tài sản ngắn hạn của Công ty là 623,48 tỷ VND, lỗ lũy kế là 1.129,82 tỷ VND, chỉ tiêu vốn chủ sở hữu âm 423,17 tỷ VND. Các khoản nợ vay đã quá hạn thanh toán 190 tỷ VND. Công ty chưa có phương án hiệu quả để khắc phục khả năng thanh khoản cũng như tìm kiếm được nguồn tiền để thanh toán cho các khoản vay đến hạn trong vòng 12 tháng tới trong điều kiện hoạt động bình thường.'),
('VTA_2015_consolidated', 'VTA', 2015, 'consolidated', 'VIETVALUES', 'unqualified', 0, NULL),
('VST_2024_consolidated', 'VST', 2024, 'consolidated', 'Công ty TNHH Kiểm toán AASC', 'qualified', 1, 'Tại thời điểm 31/12/2024, nợ ngắn hạn vượt quá tài sản ngắn hạn 734,51 tỷ VND, lỗ lũy kế 1.375,76 tỷ VND, vốn chủ sở hữu âm 669,11 tỷ VND. Nợ vay quá hạn thanh toán 218,72 tỷ VND. Công ty chưa có phương án hiệu quả để khắc phục khả năng thanh khoản và thanh toán khoản vay đến hạn trong 12 tháng tới.'),
('VST_2023_parent', 'VST', 2023, 'parent', 'Công ty TNHH Hãng Kiểm toán AASC', 'qualified', 1, 'Tại thời điểm 31/12/2023, nợ ngắn hạn đã vượt quá tài sản ngắn hạn là 1.008 tỷ đồng, lỗ lũy kế là 1.595 tỷ đồng, chỉ tiêu vốn chủ sở hữu âm 908 tỷ đồng. Các khoản nợ vay đã quá hạn thanh toán lên tới 279 tỷ đồng, chi phí lãi vay phải trả cho các khoản vay quá hạn là 749 tỷ đồng. Công ty đã có phương án tái cơ cấu tài chính nhưng chưa xác định được tính hiệu quả.'),
('VST_2023_consolidated', 'VST', 2023, 'consolidated', 'AASC Auditing Firm', 'qualified', 1, 'Tại thời điểm 31/12/2023, nợ ngắn hạn vượt tài sản ngắn hạn 970 tỷ đồng, lỗ lũy kế 1,592 tỷ đồng, vốn chủ sở hữu âm 905 tỷ đồng. Nợ vay quá hạn thanh toán 279 tỷ đồng, chi phí lãi vay phải trả 749 tỷ đồng. Công ty có phương án tái cơ cấu tài chính nhưng chưa xác định hiệu quả.'),
('VST_2021_parent', 'VST', 2021, 'parent', 'AASC Auditing Firm', 'qualified', 1, 'Tại thời điểm 31/12/2021, nợ ngắn hạn đã vượt quá tài sản ngắn hạn của Công ty là 2.148 tỷ đồng, lỗ lũy kế là 2.370 tỷ đồng, chỉ tiêu vốn chủ âm 1.726 tỷ đồng; lưu chuyển tiền thuần trong năm trên báo cáo lưu chuyển tiền tệ âm 548 triệu đồng. Các khoản nợ vay đã quá hạn thanh toán lên tới 824 tỷ đồng, chi phí lãi vay phải trả cho các khoản vay quá hạn này là 1.105 tỷ đồng. Công ty chưa có phương án hiệu quả để khắc phục khả năng thanh khoản cũng như tìm kiếm được nguồn tiền để thanh toán cho các khoản vay đến hạn trong vòng 12 tháng tới trong điều kiện hoạt động bình thường. Công ty cũng đang đối mặt với các vụ kiện của Ngân hàng về việc phải thanh toán ngay các khoản vay. Những sự kiện này, cùng với các vấn đề được nêu ở Thuyết minh số 1, cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của Công ty.'),
('VST_2022_consolidated', 'VST', 2022, 'consolidated', 'AASC', 'qualified', 1, 'Tại thời điểm 31/12/2022, nợ ngắn hạn đã vượt quá tài sản ngắn hạn của Công ty là 1.519 tỷ đồng, lỗ lũy kế là 2.159 tỷ đồng, chỉ tiêu vốn chủ âm 1.514 tỷ đồng. Đồng thời các khoản nợ vay đã quá hạn thanh toán lên tới 332 tỷ đồng. Chi phí lãi vay phải trả cho các khoản vay quá hạn này là 1.204 tỷ đồng. Công ty đang triển khai phương án hiệu quả để khắc phục khả năng thanh khoản nhưng gặp khó khăn trong việc tìm kiếm được nguồn tiền để thanh toán cho các khoản vay đến hạn trong vòng 12 tháng tới trong điều kiện hoạt động bình thường.');
INSERT OR REPLACE INTO `audit_reports` (`id`, `ticker`, `year`, `report_type`, `auditor_name`, `audit_opinion`, `going_concern_issue`, `going_concern_detail`) VALUES
('VST_2021_consolidated', 'VST', 2021, 'consolidated', 'AASC Auditing Firm', 'qualified', 1, 'Công ty chưa có phương án hiệu quả để khắc phục khả năng thanh khoản cũng như tìm kiếm được nguồn tiền để thanh toán cho các khoản vay đến hạn trong vòng 12 tháng tới trong điều kiện hoạt động bình thường.'),
('VST_2020_consolidated', 'VST', 2020, 'consolidated', 'AASC', 'qualified', 1, 'Nợ ngắn hạn vượt tài sản ngắn hạn 2.133 tỷ đồng, lỗ lũy kế 2.361 tỷ đồng, vốn chủ sở hữu âm 1.716 tỷ đồng, lưu chuyển tiền thuần âm 16 tỷ đồng. Các khoản nợ vay đã quá hạn thanh toán là 793 tỷ đồng, công ty đang bị kiện bởi ngân hàng và chưa có phương án hiệu quả để khắc phục khả năng thanh khoản.'),
('VST_2019_consolidated', 'VST', 2019, 'consolidated', 'Hãng Kiểm toán AASC', 'qualified', 1, 'Tại thời điểm 31/12/2019, nợ ngắn hạn đã vượt quá tài sản ngắn hạn của Công ty là 1.893 tỷ đồng, lỗ lũy kế là 2.053 tỷ đồng, chỉ tiêu vốn chủ đã bị âm 1.429 tỷ đồng. Đồng thời tại thuyết minh số 19 - Vay, các khoản nợ vay đã quá hạn thanh toán lên tới 736 tỷ đồng, của Ngân hàng Phát triển Việt Nam và Ngân hàng TMCP Á Châu.'),
('VST_2018_consolidated', 'VST', 2018, 'consolidated', 'VIETVALUES', 'qualified', 1, 'Năm tài chính kết thúc ngày 31 tháng 12 năm 2018, Tập đoàn tiếp tục lỗ với số tiền 255.299.656.797 VND và khoản lỗ lũy kế đến ngày 31 tháng 12 năm 2018 là 1.780.778.706.889 VND. Ngoài ra tại ngày 31 tháng 12 năm 2018, nợ ngắn hạn lớn hơn tài sản ngắn hạn với số tiền 1.899.127.933.882 VND. Các khoản nợ vay đã quá hạn thanh toán, Tập đoàn đang đàm phán lại nhưng chưa có thỏa thuận tài chính thay thế.'),
('VST_2015_parent', 'VST', 2015, 'parent', 'Công ty TNHH Kiểm toán và Kế toán Hà Nội - CPA Hà Nội', 'unqualified', 1, 'Báo cáo tài chính của Công ty cổ phần Vận tải và Thuê tàu biển Việt Nam cho năm tài chính 2015 được lập dựa trên giả định hoạt động liên tục. Đến cuối năm tài chính 2015, Công ty có nhiều biện pháp được triển khai để tái cơ cấu doanh nghiệp. Trong năm tài chính tiếp theo, doanh nghiệp khẳng định tiếp tục hoạt động liên tục nhờ các biện pháp triển khai đang thực hiện có hiệu quả.'),
('VST_2015_consolidated', 'VST', 2015, 'consolidated', 'Công ty TNHH Kiểm toán và Kế toán Hà Nội - CPA Hà Nội', 'unqualified', 1, 'Báo cáo tài chính được lập dựa trên giả định hoạt động liên tục. Công ty có nhiều biện pháp được triển khai để tái cơ cấu doanh nghiệp và khẳng định tiếp tục hoạt động liên tục.'),
