('VSG_2024_consolidated', 'VSG', 2024, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn A&C', 'disclaimer', 1, 'Năm tài chính kết thúc ngày 31 tháng 12 năm 2024 Công ty tiếp tục bị lỗ 69,793,438,920 VND và khoản lỗ lũy kế đến ngày 31 tháng 12 năm 2024 là 934,719,728,207 VND, vượt vốn góp của chủ sở hữu 767,520,103,053 VND. Nợ ngắn hạn lớn hơn tài sản ngắn hạn 797,076,675,515 VND. Công ty đã hoàn trả tất cả tàu đi thuê từ Ngân hàng TMCP Hàng Hải Việt Nam từ ngày 06 tháng 02 năm 2024, do vậy sẽ không còn phát sinh doanh thu cho thuê tàu. Các điều kiện này cho thấy sự tồn tại của các yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của Công ty.'),
('VSG_2025_consolidated', 'VSG', 2025, 'consolidated', 'Công ty TNHH Dịch vụ Tư vấn Tài chính Kế toán và Kiểm toán Phía Nam (AASCS)', 'disclaimer', 1, 'Số lỗ luỹ kế tại thời điểm 31/12/2025 là 984.288.733.480 VND đã vượt số vốn điều lệ và vốn chủ sở hữu. Nợ phải trả lớn hơn Tổng tài sản là 817.089.108.326 VND, như vậy Công ty đã không duy trì được khả năng thanh toán. Ngoài ra Nợ ngắn hạn lớn hơn Tài sản ngắn hạn 844.947.103.580 VND, như vậy khả năng thanh toán nợ ngắn hạn của Công ty cũng không đảm bảo. Thêm vào đó, kể từ ngày 06/02/2024, Công ty cũng đã hoàn trả tất cả tàu đi thuê từ Ngân hàng TMCP Hàng Hải Việt Nam - Chi nhánh TP.HCM, do đó sẽ không còn phát sinh doanh thu cho thuê tàu từ thời điểm này.'),
('VSG_2022_consolidated', 'VSG', 2022, 'consolidated', 'CÔNG TY TNHH KIỂM TOÁN VÀ TƯ VÁN A&C', 'unqualified', 0, NULL),
('VSG_2023_consolidated', 'VSG', 2023, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn A&C', 'unqualified', 0, NULL),
('VSG_2021_consolidated', 'VSG', 2021, 'consolidated', 'A&C Auditing and Consulting Co., Ltd.', 'qualified', 1, 'Công ty tiếp tục bị lỗ 103.871.857.393 VND và khoản lỗ luỹ kế đến ngày 31 tháng 12 năm 2021 là 701.655.399.367 VND, vượt vốn góp của chủ sở hữu 534.455.774.213 VND. Ngoài ra tại ngày 31 tháng 12 năm 2021 nợ ngắn hạn lớn hơn tài sản ngắn hạn một khoản 570.411.254.471 VND. Những điều kiện này cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của Công ty.'),
('VSG_2020_consolidated', 'VSG', 2020, 'consolidated', 'A&C Auditing and Consulting Co., Ltd.', 'qualified', 1, 'Công ty tiếp tục bị lỗ 39.593.803.277 VND và khoản lỗ lũy kế đến ngày 31 tháng 12 năm 2020 là 597.783.541.974 VND, vượt vốn chủ sở hữu 430.583.916.820 VND. Ngoài ra, nợ ngắn hạn lớn hơn tài sản ngắn hạn một khoản là 554.937.300.931 VND. Công ty đang đàm phán với Ngân hàng TMCP Hàng hải Việt Nam để có kế hoạch trả nợ phù hợp với tình hình hoạt động kinh doanh.'),
('VSG_2019_consolidated', 'VSG', 2019, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn A&C (Baker Tilly A&C)', 'unqualified', 1, 'Công ty tiếp tục bị lỗ lũy kế đến ngày 31 tháng 12 năm 2019 là 558.189.738.697 VND, vượt vốn chủ sở hữu 390.990.113.543 VND. Nợ ngắn hạn lớn hơn tài sản ngắn hạn 577.259.103.620 VND. Các yếu tố này cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của Công ty.'),
('VSG_2018_consolidated', 'VSG', 2018, 'consolidated', 'A&C Auditing and Consulting Co., Ltd.', 'unqualified', 1, 'Trong năm tài chính kết thúc ngày 31 tháng 12 năm 2018 Công ty tiếp tục bị lỗ 54.216.871.590 VND và khoản lỗ lũy kế đến ngày 31 tháng 12 năm 2018 là 523.776.736.851 VND. Ngoài ra tại ngày 31 tháng 12 năm 2018 nợ ngắn hạn lớn hơn tài sản ngắn hạn 527.934.099.738 VND.');
